with open("/tmp/brandrise-prep-inject.csv", "w", encoding="utf-8", newline="") as f:
    w = csv.writer(f, quoting=csv.QUOTE_ALL)
    w.writerow(["No", "신청자", "회사/브랜드", "Tier", "한 줄", "핵심 페인", "제안 + 미팅 첫 질문", "파일"])
    for r in rows:
        no, name, brand, tier, oneline, pain, suggest, file = r
        merged_prep = f"[{tier}] {oneline}\nPain: {pain}\n{suggest}"
        w.writerow([no, name, brand, tier, oneline, pain, suggest, file])

# Also write a paste-ready TSV with just one PREP column (for direct sheet paste)
with open("/tmp/brandrise-prep-paste.tsv", "w", encoding="utf-8") as f:
    for r in rows:
        no, name, brand, tier, oneline, pain, suggest, file = r
        # Single-cell merged content
        cell = f"[{tier}] {oneline}\nPain: {pain}\n{suggest}"
        # In TSV, multi-line cell needs to be quoted with " and internal " doubled
        cell_escaped = cell.replace('"', '""')
        f.write(f'"{cell_escaped}"\n')

